import { useState } from 'react';

/**
 * ============================================================================
 * TECHNICIAN LAYOUT COMPONENT
 * ============================================================================
 * 
 * PURPOSE:
 * Provides the permanent layout shell for technician-level users.
 * Technicians investigate systems, validate AI findings, and collect evidence.
 * They do NOT make financial decisions or approve replacements.
 * 
 * RESPONSIBILITIES:
 * - Render fixed sidebar with work-focused navigation
 * - Render operational header (search, notifications, shift status)
 * - Render main content area for child pages
 * - Display agent connectivity and system status
 * 
 * KEY DIFFERENCES FROM ADMIN LAYOUT:
 * - No financial controls
 * - No organization selector
 * - Work-focused navigation (assigned systems, investigations)
 * - Shift status indicator
 * - Task-oriented badges (pending assignments)
 * 
 * FUTURE ENHANCEMENTS:
 * - Real-time task assignment notifications
 * - Integration with mobile devices for field work
 * - Voice notes and photo upload capabilities
 * - Offline mode for remote locations
 */

// ============================================================================
// PLACEHOLDER CHILD COMPONENTS
// ============================================================================

function TechnicianDashboard() {
  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-900 mb-4">Technician Dashboard</h1>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
        <div className="bg-white rounded-lg border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-3">
            <span className="text-3xl">📋</span>
            <span className="text-3xl font-bold text-blue-600">8</span>
          </div>
          <p className="text-sm text-gray-600">Tasks Assigned Today</p>
        </div>
        <div className="bg-white rounded-lg border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-3">
            <span className="text-3xl">✅</span>
            <span className="text-3xl font-bold text-green-600">5</span>
          </div>
          <p className="text-sm text-gray-600">Completed This Week</p>
        </div>
        <div className="bg-white rounded-lg border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-3">
            <span className="text-3xl">⏱️</span>
            <span className="text-3xl font-bold text-orange-600">3</span>
          </div>
          <p className="text-sm text-gray-600">Urgent Investigations</p>
        </div>
      </div>
      <div className="bg-white rounded-lg border border-gray-200 p-8 text-center">
        <p className="text-gray-600">📊 Your performance metrics and recent activity</p>
      </div>
    </div>
  );
}

function AssignedSystems() {
  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-900 mb-4">Assigned Systems</h1>
      <div className="bg-white rounded-lg border border-gray-200 p-8 text-center">
        <p className="text-gray-600">💻 List of systems assigned for investigation</p>
      </div>
    </div>
  );
}

function InvestigationLogs() {
  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-900 mb-4">Investigation Logs</h1>
      <div className="bg-white rounded-lg border border-gray-200 p-8 text-center">
        <p className="text-gray-600">📝 Historical investigation reports and findings</p>
      </div>
    </div>
  );
}

// ============================================================================
// MAIN TECHNICIAN LAYOUT COMPONENT
// ============================================================================

function TechnicianLayout() {
  // ===== NAVIGATION STATE =====
  const [activeNav, setActiveNav] = useState('dashboard');
  
  // ===== UI CONTROL STATES =====
  const [notificationsOpen, setNotificationsOpen] = useState(false);
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  
  // ===== DUMMY DATA =====
  // TODO: Replace with real-time data from backend
  const technicianInfo = {
    name: 'Alex Rodriguez',
    id: 'TECH-447',
    shift: 'Active', // 'Active' | 'Break' | 'Offline'
    avatar: 'AR'
  };
  
  const pendingCounts = {
    dashboard: 0,
    assigned: 8,
    logs: 2
  };
  
  const notifications = [
    {
      id: 1,
      type: 'urgent',
      title: 'Urgent: SYS-8472 requires immediate attention',
      time: '5m ago',
      unread: true
    },
    {
      id: 2,
      type: 'assignment',
      title: 'New system assigned: SYS-9031',
      time: '1h ago',
      unread: true
    },
    {
      id: 3,
      type: 'update',
      title: 'Investigation log approved for SYS-7720',
      time: '3h ago',
      unread: false
    }
  ];
  
  // Navigation menu configuration
  const navItems = [
    {
      id: 'dashboard',
      label: 'Dashboard',
      icon: '📊',
      badge: pendingCounts.dashboard
    },
    {
      id: 'assigned',
      label: 'Assigned Systems',
      icon: '💻',
      badge: pendingCounts.assigned
    },
    {
      id: 'logs',
      label: 'Investigation Logs',
      icon: '📝',
      badge: pendingCounts.logs
    }
  ];
  
  // ===== RENDER CHILD CONTENT =====
  const renderContent = () => {
    switch(activeNav) {
      case 'dashboard':
        return <TechnicianDashboard />;
      case 'assigned':
        return <AssignedSystems />;
      case 'logs':
        return <InvestigationLogs />;
      default:
        return <TechnicianDashboard />;
    }
  };
  
  // Shift status styling
  const getShiftStatusStyle = () => {
    switch(technicianInfo.shift) {
      case 'Active':
        return 'bg-green-100 text-green-700 border-green-200';
      case 'Break':
        return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case 'Offline':
        return 'bg-gray-100 text-gray-700 border-gray-200';
      default:
        return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">
      
      {/* ================================================================
          LEFT SIDEBAR - WORK NAVIGATION
          ================================================================
      */}
      <aside className="w-72 bg-gradient-to-b from-gray-900 to-gray-800 text-white flex flex-col flex-shrink-0 shadow-2xl">
        
        {/* BRANDING SECTION */}
        <div className="p-6 border-b border-gray-700">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl flex items-center justify-center shadow-lg">
              <span className="text-2xl font-bold">M</span>
            </div>
            <div>
              <h1 className="text-xl font-bold">MaintenanceAI</h1>
              <p className="text-xs text-gray-400">Technician Portal</p>
            </div>
          </div>
        </div>
        
        {/* TECHNICIAN INFO CARD */}
        <div className="p-4 mx-3 mt-4 bg-gray-800/50 rounded-lg border border-gray-700">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-gradient-to-br from-blue-400 to-blue-500 rounded-full flex items-center justify-center font-bold text-lg shadow-md">
              {technicianInfo.avatar}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-semibold text-white truncate">
                {technicianInfo.name}
              </p>
              <p className="text-xs text-gray-400">{technicianInfo.id}</p>
            </div>
          </div>
          <div className="mt-3 flex items-center justify-between">
            <span className="text-xs text-gray-400">Shift Status</span>
            <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-semibold border ${getShiftStatusStyle()}`}>
              <span className="w-1.5 h-1.5 bg-current rounded-full mr-1.5"></span>
              {technicianInfo.shift}
            </span>
          </div>
        </div>
        
        {/* NAVIGATION MENU */}
        <nav className="flex-1 overflow-y-auto py-4">
          <ul className="space-y-1 px-3">
            {navItems.map((item) => (
              <li key={item.id}>
                <button
                  onClick={() => setActiveNav(item.id)}
                  className={`w-full flex items-center justify-between px-4 py-3 rounded-lg transition-all duration-200 group ${
                    activeNav === item.id
                      ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/30'
                      : 'text-gray-300 hover:bg-gray-700/50 hover:text-white'
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <span className="text-xl">{item.icon}</span>
                    <span className="font-medium text-sm">{item.label}</span>
                  </div>
                  {item.badge > 0 && (
                    <span className={`px-2 py-0.5 rounded-full text-xs font-bold ${
                      activeNav === item.id
                        ? 'bg-white text-blue-600'
                        : 'bg-red-500 text-white group-hover:bg-red-600'
                    }`}>
                      {item.badge}
                    </span>
                  )}
                </button>
              </li>
            ))}
          </ul>
          
          {/* QUICK ACTIONS SECTION */}
          <div className="px-3 mt-6">
            <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider px-4 mb-3">
              Quick Actions
            </p>
            <div className="space-y-2">
              <button className="w-full px-4 py-2.5 bg-gray-700/50 hover:bg-gray-700 rounded-lg text-left text-sm text-gray-300 hover:text-white transition-colors flex items-center gap-3">
                <span>📸</span>
                <span>Capture Evidence</span>
              </button>
              <button className="w-full px-4 py-2.5 bg-gray-700/50 hover:bg-gray-700 rounded-lg text-left text-sm text-gray-300 hover:text-white transition-colors flex items-center gap-3">
                <span>🎤</span>
                <span>Voice Note</span>
              </button>
              <button className="w-full px-4 py-2.5 bg-gray-700/50 hover:bg-gray-700 rounded-lg text-left text-sm text-gray-300 hover:text-white transition-colors flex items-center gap-3">
                <span>📋</span>
                <span>Submit Report</span>
              </button>
            </div>
          </div>
        </nav>
        
        {/* SIDEBAR FOOTER */}
        <div className="p-4 border-t border-gray-700">
          <div className="flex items-center gap-2 mb-3">
            <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></div>
            <span className="text-xs text-gray-400">System Connected</span>
          </div>
          <div className="text-xs text-gray-500">
            <p>Platform v1.0.0</p>
            <p className="mt-1">Last sync: 2m ago</p>
          </div>
        </div>
      </aside>

      {/* ================================================================
          RIGHT SIDE - HEADER + CONTENT + FOOTER
          ================================================================
      */}
      <div className="flex-1 flex flex-col overflow-hidden">
        
        {/* ================================================================
            HEADER - OPERATIONAL CONTROLS
            ================================================================
        */}
        <header className="bg-white border-b border-gray-200 px-6 py-3 flex items-center justify-between sticky top-0 z-10 shadow-sm">
          
          {/* LEFT - SEARCH */}
          <div className="flex-1 max-w-xl">
            <div className="relative">
              <input
                type="text"
                placeholder="Search system ID (e.g., SYS-8472)..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    console.log('Search for system:', searchQuery);
                    // TODO: Navigate to system details or trigger search
                  }
                }}
                className="w-full px-4 py-2 pl-10 bg-gray-50 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
              />
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 text-lg">
                🔍
              </span>
              {searchQuery && (
                <button
                  onClick={() => setSearchQuery('')}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                >
                  ✕
                </button>
              )}
            </div>
          </div>
          
          {/* RIGHT - NOTIFICATIONS & USER */}
          <div className="flex items-center gap-4 ml-6">
            
            {/* Current Time */}
            <div className="hidden md:flex flex-col items-end">
              <span className="text-xs text-gray-500">Current Time</span>
              <span className="text-sm font-semibold text-gray-900">
                {new Date().toLocaleTimeString('en-US', { 
                  hour: '2-digit', 
                  minute: '2-digit'
                })}
              </span>
            </div>
            
            {/* Notifications */}
            <div className="relative">
              <button
                onClick={() => setNotificationsOpen(!notificationsOpen)}
                className="relative p-2 hover:bg-gray-100 rounded-lg transition-colors"
              >
                <span className="text-2xl">🔔</span>
                {notifications.filter(n => n.unread).length > 0 && (
                  <span className="absolute top-1 right-1 w-5 h-5 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center">
                    {notifications.filter(n => n.unread).length}
                  </span>
                )}
              </button>
              
              {/* Notifications Dropdown */}
              {notificationsOpen && (
                <div className="absolute top-full right-0 mt-2 w-80 bg-white border border-gray-200 rounded-lg shadow-xl z-20">
                  <div className="p-3 border-b border-gray-200 flex items-center justify-between">
                    <h3 className="font-semibold text-sm text-gray-900">Notifications</h3>
                    <button className="text-xs text-blue-600 hover:text-blue-700">
                      Mark all read
                    </button>
                  </div>
                  <div className="max-h-96 overflow-y-auto">
                    {notifications.map((notif) => (
                      <button
                        key={notif.id}
                        onClick={() => {
                          console.log('Open notification:', notif.id);
                          setNotificationsOpen(false);
                        }}
                        className={`w-full text-left p-3 hover:bg-gray-50 transition-colors border-b border-gray-100 ${
                          notif.unread ? 'bg-blue-50/50' : ''
                        }`}
                      >
                        <div className="flex items-start gap-2">
                          <span className="text-lg flex-shrink-0">
                            {notif.type === 'urgent' ? '🚨' : notif.type === 'assignment' ? '📋' : '✅'}
                          </span>
                          <div className="flex-1 min-w-0">
                            <p className={`text-sm ${notif.unread ? 'font-semibold text-gray-900' : 'text-gray-700'}`}>
                              {notif.title}
                            </p>
                            <p className="text-xs text-gray-500 mt-1">{notif.time}</p>
                          </div>
                          {notif.unread && (
                            <div className="w-2 h-2 bg-blue-600 rounded-full flex-shrink-0 mt-1"></div>
                          )}
                        </div>
                      </button>
                    ))}
                  </div>
                  <div className="p-2 border-t border-gray-200">
                    <button className="w-full py-2 text-center text-sm text-blue-600 hover:text-blue-700 font-medium">
                      View All Notifications
                    </button>
                  </div>
                </div>
              )}
            </div>
            
            {/* User Menu */}
            <div className="relative">
              <button
                onClick={() => setUserMenuOpen(!userMenuOpen)}
                className="flex items-center gap-3 p-2 hover:bg-gray-100 rounded-lg transition-colors"
              >
                <div className="w-9 h-9 bg-gradient-to-br from-blue-500 to-blue-600 text-white rounded-full flex items-center justify-center font-semibold text-sm shadow-md">
                  {technicianInfo.avatar}
                </div>
                <div className="hidden lg:flex flex-col items-start">
                  <span className="text-sm font-semibold text-gray-900">
                    {technicianInfo.name}
                  </span>
                  <span className="text-xs text-gray-500">{technicianInfo.id}</span>
                </div>
                <span className="text-gray-500 text-sm">▼</span>
              </button>
              
              {/* User Dropdown */}
              {userMenuOpen && (
                <div className="absolute top-full right-0 mt-2 w-56 bg-white border border-gray-200 rounded-lg shadow-xl z-20">
                  <div className="p-3 border-b border-gray-200">
                    <p className="text-sm font-semibold text-gray-900">{technicianInfo.name}</p>
                    <p className="text-xs text-gray-500">{technicianInfo.id}</p>
                    <div className="mt-2">
                      <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-semibold border ${getShiftStatusStyle()}`}>
                        <span className="w-1.5 h-1.5 bg-current rounded-full mr-1.5"></span>
                        {technicianInfo.shift}
                      </span>
                    </div>
                  </div>
                  
                  <button
                    onClick={() => {
                      setUserMenuOpen(false);
                      console.log('Change shift status');
                    }}
                    className="w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors text-sm text-gray-700"
                  >
                    🔄 Change Shift Status
                  </button>
                  
                  <button
                    onClick={() => {
                      setUserMenuOpen(false);
                      console.log('Navigate to: Profile');
                    }}
                    className="w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors text-sm text-gray-700"
                  >
                    👤 My Profile
                  </button>
                  
                  <button
                    onClick={() => {
                      setUserMenuOpen(false);
                      console.log('Navigate to: Settings');
                    }}
                    className="w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors text-sm text-gray-700"
                  >
                    ⚙️ Settings
                  </button>
                  
                  <div className="border-t border-gray-200">
                    <button
                      onClick={() => {
                        setUserMenuOpen(false);
                        console.log('Logout');
                      }}
                      className="w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors text-sm text-red-600 font-medium rounded-b-lg"
                    >
                      🚪 Sign Out
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* ================================================================
            MAIN CONTENT AREA
            ================================================================
        */}
        <main className="flex-1 overflow-y-auto bg-gray-50">
          <div className="max-w-[1600px] mx-auto">
            {renderContent()}
          </div>
        </main>

        {/* ================================================================
            FOOTER
            ================================================================
        */}
        <footer className="bg-white border-t border-gray-200 px-6 py-3">
          <div className="max-w-[1600px] mx-auto flex items-center justify-between text-sm">
            <div className="flex items-center gap-6">
              <span className="text-gray-600">© 2025 MaintenanceAI</span>
              <span className="text-gray-400">|</span>
              <span className="text-gray-600">Platform v1.0.0</span>
              <span className="text-gray-400">|</span>
              <span className="px-2 py-1 bg-green-100 text-green-700 rounded text-xs font-semibold">
                Production
              </span>
            </div>
            
            <div className="flex items-center gap-6">
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                <span className="text-xs text-gray-600">Agent Connected</span>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-xs text-gray-600">Last sync: 2m ago</span>
              </div>
            </div>
          </div>
        </footer>
      </div>
    </div>
  );
}

export default TechnicianLayout;
